-- Откат миграции 000030: удаляем добавленные роли и их назначения.
-- Обратите внимание: miграция откатывает только объекты, которые создала,
-- поэтому исходная роль «Администратор системы» и роли «Администратор
-- проекта»/«Разработчик» из 000026 остаются нетронутыми.

-- 1. Убираем назначения проектных ролей в сидовых проектах, которые добавились
--    по должности (вернём старое поведение: все, кроме владельца, — Разработчик).
DELETE FROM member_roles
WHERE member_id IN (
    SELECT m.id FROM members m
    WHERE m.project_id IN (
        'c0000000-0000-0000-0001-000000000000'::uuid,
        'c0000000-0000-0000-0002-000000000000'::uuid,
        'c0000000-0000-0000-0003-000000000000'::uuid,
        'c0000000-0000-0000-0004-000000000000'::uuid
    )
);

INSERT INTO member_roles (member_id, role_id)
SELECT
    m.id,
    CASE
        WHEN p.owner_id = m.user_id
            THEN ('e0000000-0000-0000-' || lpad(split_part(m.project_id::text, '-', 4), 4, '0') || '-000000000001')::uuid
        ELSE
            ('e0000000-0000-0000-' || lpad(split_part(m.project_id::text, '-', 4), 4, '0') || '-000000000002')::uuid
    END
FROM members m
JOIN projects p ON p.id = m.project_id
WHERE m.project_id IN (
    'c0000000-0000-0000-0001-000000000000'::uuid,
    'c0000000-0000-0000-0002-000000000000'::uuid,
    'c0000000-0000-0000-0003-000000000000'::uuid,
    'c0000000-0000-0000-0004-000000000000'::uuid
)
ON CONFLICT DO NOTHING;

-- 2. Убираем назначения новых системных ролей сидовым пользователям.
DELETE FROM user_roles
WHERE role_id IN (
    'a0000000-0000-0000-0000-000000000002',
    'a0000000-0000-0000-0000-000000000003',
    'a0000000-0000-0000-0000-000000000004',
    'a0000000-0000-0000-0000-000000000005'
);

-- 3. Удаляем проектные роли, созданные миграцией (права и сами роли).
DELETE FROM role_permissions
WHERE role_id IN (
    -- MOB/MKT/INF/SITE: Менеджер, Тестировщик, Аналитик, Наблюдатель
    'e0000000-0000-0000-0001-000000000003','e0000000-0000-0000-0001-000000000004','e0000000-0000-0000-0001-000000000005','e0000000-0000-0000-0001-000000000006',
    'e0000000-0000-0000-0002-000000000003','e0000000-0000-0000-0002-000000000004','e0000000-0000-0000-0002-000000000005','e0000000-0000-0000-0002-000000000006',
    'e0000000-0000-0000-0003-000000000003','e0000000-0000-0000-0003-000000000004','e0000000-0000-0000-0003-000000000005','e0000000-0000-0000-0003-000000000006',
    'e0000000-0000-0000-0004-000000000003','e0000000-0000-0000-0004-000000000004','e0000000-0000-0000-0004-000000000005','e0000000-0000-0000-0004-000000000006',
    -- Шаблонные: Scrum
    'a1200000-0000-0000-0000-000000000002','a1200000-0000-0000-0000-000000000003','a1200000-0000-0000-0000-000000000004','a1200000-0000-0000-0000-000000000005','a1200000-0000-0000-0000-000000000006',
    -- Шаблонные: Kanban
    'a2200000-0000-0000-0000-000000000002','a2200000-0000-0000-0000-000000000003','a2200000-0000-0000-0000-000000000004','a2200000-0000-0000-0000-000000000005','a2200000-0000-0000-0000-000000000006',
    -- Системные
    'a0000000-0000-0000-0000-000000000002','a0000000-0000-0000-0000-000000000003','a0000000-0000-0000-0000-000000000004','a0000000-0000-0000-0000-000000000005'
);

DELETE FROM roles WHERE id IN (
    'e0000000-0000-0000-0001-000000000003','e0000000-0000-0000-0001-000000000004','e0000000-0000-0000-0001-000000000005','e0000000-0000-0000-0001-000000000006',
    'e0000000-0000-0000-0002-000000000003','e0000000-0000-0000-0002-000000000004','e0000000-0000-0000-0002-000000000005','e0000000-0000-0000-0002-000000000006',
    'e0000000-0000-0000-0003-000000000003','e0000000-0000-0000-0003-000000000004','e0000000-0000-0000-0003-000000000005','e0000000-0000-0000-0003-000000000006',
    'e0000000-0000-0000-0004-000000000003','e0000000-0000-0000-0004-000000000004','e0000000-0000-0000-0004-000000000005','e0000000-0000-0000-0004-000000000006',
    'a1200000-0000-0000-0000-000000000002','a1200000-0000-0000-0000-000000000003','a1200000-0000-0000-0000-000000000004','a1200000-0000-0000-0000-000000000005','a1200000-0000-0000-0000-000000000006',
    'a2200000-0000-0000-0000-000000000002','a2200000-0000-0000-0000-000000000003','a2200000-0000-0000-0000-000000000004','a2200000-0000-0000-0000-000000000005','a2200000-0000-0000-0000-000000000006',
    'a0000000-0000-0000-0000-000000000002','a0000000-0000-0000-0000-000000000003','a0000000-0000-0000-0000-000000000004','a0000000-0000-0000-0000-000000000005'
);
